import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.FieldNamingStrategy;
import com.google.gson.FieldNamingPolicy;
import com.google.gson.Gson;

class GsonFieldNamingStrategyTest {

  @Test
  void testFieldNamingStrategy_Default() {
    Gson gson = new Gson();
    FieldNamingStrategy strategy = gson.fieldNamingStrategy();
    assertNotNull(strategy);
    assertEquals(FieldNamingPolicy.IDENTITY, strategy);
  }

  @Test
  void testFieldNamingStrategy_CustomStrategy() throws Exception {
    FieldNamingStrategy customStrategy = field -> "customName";
    // Use reflection to create Gson instance with custom fieldNamingStrategy
    Gson gson = createGsonWithFieldNamingStrategy(customStrategy);
    FieldNamingStrategy strategy = gson.fieldNamingStrategy();
    assertNotNull(strategy);
    assertSame(customStrategy, strategy);
  }

  private Gson createGsonWithFieldNamingStrategy(FieldNamingStrategy strategy) throws Exception {
    // Use reflection to invoke the package-private constructor with fieldNamingStrategy parameter
    // The constructor signature is:
    // Gson(Excluder excluder, FieldNamingStrategy fieldNamingStrategy,
    // Map<Type, InstanceCreator<?>> instanceCreators, boolean serializeNulls,
    // boolean complexMapKeySerialization, boolean generateNonExecutableGson, boolean htmlSafe,
    // boolean prettyPrinting, boolean lenient, boolean serializeSpecialFloatingPointValues,
    // boolean useJdkUnsafe, LongSerializationPolicy longSerializationPolicy, String datePattern,
    // int dateStyle, int timeStyle, List<TypeAdapterFactory> builderFactories,
    // List<TypeAdapterFactory> builderHierarchyFactories, List<TypeAdapterFactory> factoriesToBeAdded,
    // ToNumberStrategy objectToNumberStrategy, ToNumberStrategy numberToNumberStrategy,
    // List<ReflectionAccessFilter> reflectionFilters)
    Class<Gson> gsonClass = Gson.class;
    java.lang.reflect.Constructor<Gson> constructor = gsonClass.getDeclaredConstructor(
        com.google.gson.internal.Excluder.class,
        FieldNamingStrategy.class,
        java.util.Map.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        com.google.gson.LongSerializationPolicy.class,
        String.class,
        int.class,
        int.class,
        java.util.List.class,
        java.util.List.class,
        java.util.List.class,
        com.google.gson.ToNumberStrategy.class,
        com.google.gson.ToNumberStrategy.class,
        java.util.List.class
    );
    constructor.setAccessible(true);
    return constructor.newInstance(
        null, // Excluder
        strategy,
        java.util.Collections.emptyMap(),
        false, // serializeNulls
        false, // complexMapKeySerialization
        false, // generateNonExecutableGson
        true,  // htmlSafe
        false, // prettyPrinting
        false, // lenient
        false, // serializeSpecialFloatingPointValues
        true,  // useJdkUnsafe
        null,  // LongSerializationPolicy
        null,  // datePattern
        0,     // dateStyle
        0,     // timeStyle
        java.util.Collections.emptyList(),
        java.util.Collections.emptyList(),
        java.util.Collections.emptyList(),
        null,  // objectToNumberStrategy
        null,  // numberToNumberStrategy
        java.util.Collections.emptyList()
    );
  }
}
